 32	        bounds: input.bounds,
 33	        signatureUsedThisRun: input.runContext.signatureMomentUsedThisRun,
 34	      }),
 35	    }),
 36	  );
 37	
 38	  const prompt = sections.join("\n\n");
 39	
 40	  if (prompt.length > PROMPT_MAX_CHAR_LENGTH) {
 41	    throw new Error(
 42	      `assembled prompt exceeds budget (${prompt.length} > ${PROMPT_MAX_CHAR_LENGTH} chars)`,
 43	    );
 44	  }
 45	
 46	  return prompt;
